from graphene import Object, String, Float, List, Schema
from flask import Flask
from graphene_sqlalchemy import SQLAlchemyObjectType, SQLAlchemyConnectionField
from sqlalchemy import create_engine, Column, Integer, String, Float
from sqlalchemy.ext.declarative import declarative_base

# Create the Flask app
app = Flask(__name__)

# Create the SQLAlchemy engine
engine = create_engine('sqlite:///products.db')
Base = declarative_base()

# Define the Product model
class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)
    price = Column(Float)

# Define the Category model
class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)

# Define the UserReview model
class UserReview(Base):
    __tablename__ = 'user_reviews'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    rating = Column(Integer)
    review = Column(String)

# Create the SQLAlchemy models
ProductModel = SQLAlchemyObjectType(Product)
CategoryModel = SQLAlchemyObjectType(Category)
UserReviewModel = SQLAlchemyObjectType(UserReview)

# Create the GraphQL schema
class Query(Object):
    products = SQLAlchemyConnectionField(ProductModel)
    categories = SQLAlchemyConnectionField(CategoryModel)
    user_reviews = SQLAlchemyConnectionField(UserReviewModel)

schema = Schema(query=Query)

# Create the Flask GraphQL view
@app.route('/graphql', methods=['GET', 'POST'])
def graphql():
    return schema.execute(request.data)

# Run the Flask app
if __name__ == '__main__':
    app.run(debug=True)